+import { $internal } from '../common';
+import { destroyEntity, initializeEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity, releaseEntity } from '../entity/utils/entity-index';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { World } from '../world/types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[]; cancelled?: boolean }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; traits: RelationPair[] };
+
+type Scope = { commands: Command[] };
+type DeferredState = { scopes: Scope[]; root: Scope; flushing: boolean };
+
+export type Deferred = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, ...traits: RelationPair[]): void;
+    flush(): void;
+};
+
+function state(world: World): DeferredState {
+    let value = world[$internal].deferredState as DeferredState | undefined;
+    if (!value) {
+        const root = { commands: [] };
+        value = { root, scopes: [root], flushing: false };
+        world[$internal].deferredState = value;
+    }
+    return value;
+}
+
+function scope(world: World) {
+    const value = state(world);
+    return value.scopes[value.scopes.length - 1];
+}
+
+function queue(world: World, command: Command) {
+    scope(world).commands.push(command);
+}
+
+/** Starts an isolated command scope. Query iteration uses this to avoid structural mutation. */
+export function beginDeferredScope(world: World) {
+    state(world).scopes.push({ commands: [] });
+}
+
+export function endDeferredScope(world: World) {
+    const value = state(world);
+    const current = value.scopes[value.scopes.length - 1];
+    flushScope(world, current);
+    value.scopes.pop();
+}
+
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    const value = state(world);
+    if (value.flushing || !hasPendingEntity(world, entity)) return;
+    // Flushing the active scope preserves commands in enclosing scopes.
+    flushScope(world, scope(world));
+}
+
+function hasPendingEntity(world: World, entity: Entity) {
+    return state(world).scopes.some((entry) => entry.commands.some((command) => command.entity === entity));
+}
+
+function isPendingSpawn(world: World, entity: Entity) {
+    return state(world).scopes.some((entry) =>
+        entry.commands.some((command) => command.type === 'spawn' && command.entity === entity && !command.cancelled)
+    );
+}
+
+function cancelSpawn(world: World, entity: Entity) {
+    for (const entry of state(world).scopes) {
+        for (const command of entry.commands) {
+            if (command.type === 'spawn' && command.entity === entity && !command.cancelled) {
+                command.cancelled = true;
+                releaseEntity(world[$internal].entityIndex, entity);
+                return true;
+            }
+        }
+    }
+    return false;
+}
+
+function flushScope(world: World, current: Scope) {
+    const value = state(world);
+    if (value.flushing || current.commands.length === 0) return;
+    value.flushing = true;
+    const commands = current.commands.splice(0);
+    try {
+        for (const command of commands) {
+            if (command.type === 'spawn') {
+                if (!command.cancelled) initializeEntity(world, command.entity, ...command.traits);
+                continue;
+            }
+            if (!world.has(command.entity)) continue;
+            if (command.type === 'destroy') {
+                if (command.entity === world[$internal].worldEntity) {
+                    throw new Error('Koota: The world entity cannot be destroyed by deferred commands.');
+                }
+                destroyEntity(world, command.entity);
+            } else if (command.type === 'add') {
+                addTrait(world, command.entity, ...command.traits);
+            } else if (command.type === 'remove') {
+                removeTrait(world, command.entity, ...command.traits);
+            } else {
+                for (const pair of command.traits) {
+                    const relation = pair[$internal].relation;
+                    removeTrait(world, command.entity, relation('*'));
+                    addTrait(world, command.entity, pair);
+                }
+            }
+        }
+    } finally {
+        value.flushing = false;
+    }
+}
+
+export function createDeferred(world: World): Deferred {
+    return Object.freeze({
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            queue(world, { type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            if (!cancelSpawn(world, entity)) queue(world, { type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            queue(world, { type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            queue(world, { type: 'remove', entity, traits });
+        },
+        addExclusive(entity, ...traits) {
+            queue(world, { type: 'exclusive', entity, traits });
+        },
+        flush() {
+            flushScope(world, scope(world));
+        },
+    });
+}
+
+/** Read helpers deliberately project queued commands without committing structural changes. */
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    if (!hasPendingEntity(world, entity)) return undefined;
+    if (!world.has(entity) && !isPendingSpawn(world, entity)) return false;
+    let value = isRelationPair(trait)
+        ? false
+        : isPendingSpawn(world, entity)
+          ? false
+          : hasTrait(world, entity, trait);
+    for (const entry of state(world).scopes) {
+        for (const command of entry.commands) {
+            if (command.entity !== entity) continue;
+            if (command.type === 'destroy') return false;
+            if (command.type === 'add') {
+                for (const config of command.traits) {
+                    if (isRelationPair(config)) {
+                        if (isRelationPair(trait) && samePair(config, trait)) value = true;
+                    } else if (!isRelationPair(trait) && configTrait(config) === trait) value = true;
+                }
+            } else if (command.type === 'remove') {
+                for (const config of command.traits) {
+                    if (isRelationPair(config)) {
+                        if (isRelationPair(trait) && removesPair(config, trait)) value = false;
+                    } else if (!isRelationPair(trait) && config === trait) value = false;
+                }
+            } else if (command.type === 'exclusive' && isRelationPair(trait)) {
+                for (const pair of command.traits) {
+                    if (pair[$internal].relation === trait[$internal].relation) {
+                        value = samePair(pair, trait);
+                    }
+                }
+            }
+        }
+    }
+    return value;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair) {
+    const has = hasDeferredTrait(world, entity, trait);
+    if (has === undefined) return undefined;
+    if (!has) return undefined;
+    let result = isPendingSpawn(world, entity) ? undefined : getTrait(world, entity, trait);
+    for (const entry of state(world).scopes) {
+        for (const command of entry.commands) {
+            if (command.entity !== entity || command.type !== 'add') continue;
+            for (const config of command.traits) {
+                if (isRelationPair(config)) {
+                    if (isRelationPair(trait) && samePair(config, trait)) result = config[$internal].params;
+                } else if (!isRelationPair(trait) && configTrait(config) === trait && Array.isArray(config)) {
+                    result = config[1];
+                }
+            }
+        }
+    }
+    return result;
+}
+
+function configTrait(config: ConfigurableTrait) {
+    return Array.isArray(config) ? config[0] : config;
+}
+
+function samePair(a: RelationPair, b: RelationPair) {
+    return a[$internal].relation === b[$internal].relation && a[$internal].target === b[$internal].target;
+}
+
+function removesPair(remove: RelationPair, pair: RelationPair) {
+    return remove[$internal].relation === pair[$internal].relation &&
+        (remove[$internal].target === '*' || remove[$internal].target === pair[$internal].target);
+}
