+describe('deferred commands', () => {
+    it('projects mutations and flushes them after updateEach', () => {
+        const Position = trait({ x: 'f32' });
+        const world = createWorld();
+        const entity = world.spawn(Position({ x: 1 }));
+
+        world.query(Position).updateEach((_, current) => {
+            world.deferred.add(current, Position({ x: 2 }));
+            expect(current.has(Position)).toBe(true);
+            expect(current.get(Position)).toEqual({ x: 2 });
+        });
+
+        // A deferred add preserves normal add semantics for an already-present trait.
+        expect(entity.get(Position)).toEqual({ x: 1 });
+    });
+
+    it('does not make a deferred spawn visible to queries before flush', () => {
+        const Tag = trait();
+        const world = createWorld();
+        const entity = world.deferred.spawn(Tag);
+
+        expect(entity.has(Tag)).toBe(true);
+        expect(world.query(Tag)).toHaveLength(0);
+        world.deferred.flush();
+        expect(world.query(Tag)).toEqual([entity]);
+    });
+
+    it('nullifies a spawn destroyed in the same buffer', () => {
+        const world = createWorld();
+        const entity = world.deferred.spawn();
+        world.deferred.destroy(entity);
+        world.deferred.flush();
+        expect(world.has(entity)).toBe(false);
+    });
+
+    it('replaces relation pairs through addExclusive', () => {
+        const Likes = relation();
+        const world = createWorld();
+        const entity = world.spawn();
+        const first = world.spawn();
+        const second = world.spawn();
+        entity.add(Likes(first));
+
+        world.deferred.addExclusive(entity, Likes(second));
+        world.deferred.flush();
+        expect(entity.has(Likes(first))).toBe(false);
+        expect(entity.has(Likes(second))).toBe(true);
+
+        world.deferred.addExclusive(entity, Likes('*'));
+        world.deferred.flush();
+        expect(entity.has(Likes(second))).toBe(false);
+    });
+});
